        code: '<nav>\n  <ul>\n    <li><a href="/">Home</a></li>\n    <li><a href="/about" aria-current="page">About</a></li>\n    <li><a href="/blog">Blog</a></li>\n    <li><a href="/contact">Contact</a></li>\n  </ul>\n</nav>',
