        fixCode: '// ❌ Wrong — returns every row in the table\nconst { rows } = await pool.query(\'SELECT * FROM events\')\n\n// ✅ Right — cap results and paginate\nconst { rows } = await pool.query(\n  \'SELECT id, name, created_at FROM events ORDER BY created_at DESC LIMIT $1 OFFSET $2\',\n  [pageSize, offset]\n)',
