        code: 'const page = parseInt(req.query.page) || 1\nconst pageSize = 20\nconst search = req.query.q || \'\'\n\nconst { rows } = await pool.query(\n  `SELECT id, name, email\n   FROM users\n   WHERE name ILIKE $1\n   ORDER BY name ASC\n   LIMIT $2 OFFSET $3`,\n  [`%${search}%`, pageSize, (page - 1) * pageSize]\n)\nres.json(rows)',
