    id: 'git-merge-conflicts',
    nextTopicId: 'git-undo-stash',
    title: 'Merge Conflicts',
    description: 'What happens when two branches edit the same line — and how to resolve it step by step',
    category: 'git-collab',
    color: '#5eead4',
    estimatedMinutes: 7,
    animationComponent: 'GitConflictViz',
